    47→function parseChecklist(md: string): Section[] {
    48→  const lines = md.split("\n");
    49→  const sections: Section[] = [];
    50→  let current: Section | null = null;
    51→
    52→  for (const line of lines) {
    53→    if (line.startsWith("## ")) {
    54→      current = { id: line.slice(3).trim().replace(/\s+/g, "-").toLowerCase(), title: line.slice(3).trim(), items: [], notes: [] };
    55→      sections.push(current);
    56→    } else if (current && /^- \[[ xX]\]/.test(line)) {
    57→      const done = /^- \[[xX]\]/.test(line);
    58→      const text = line.replace(/^- \[[ xX]\]\s*/, "").trim();
    59→      const priority = done ? "none" : detectPriority(text);
    60→      current.items.push({ done, text, priority, raw: line });
    61→    } else if (current && line.trim() && !line.startsWith("#") && !line.startsWith("|") && !line.startsWith("---")) {
    62→      current.notes.push(line);
    63→    }
    64→  }
    65→  return sections.filter((s) => s.items.length > 0);
    66→}
