interface PaymentEvent {
  id: string;
  mpPaymentId: string | null;
  plan: string;
  amount: number | null;
  status: string;
  description: string;
  createdAt: string;
}

const STATUS_LABEL: Record<string, { label: string; color: string }> = {
  approved: { label: "Aprobado", color: "text-green-700 bg-green-50" },
  pending:  { label: "Pendiente", color: "text-amber-700 bg-amber-50" },
  rejected: { label: "Rechazado", color: "text-red-700 bg-red-50" },
  cancelled: { label: "Cancelado", color: "text-gray-600 bg-gray-100" },
  refunded:  { label: "Reintegrado", color: "text-blue-700 bg-blue-50" },
  chargedback: { label: "Contracargo", color: "text-red-700 bg-red-50" },
  subscription_cancelled: { label: "Cancelado", color: "text-gray-600 bg-gray-100" },
};

function PaymentHistorySection() {
  const [events, setEvents] = useState<PaymentEvent[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("/api/payments/history", { credentials: "include" })
      .then(r => r.json())
      .then((d: { events: PaymentEvent[] }) => setEvents(d.events ?? []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div className="mt-6 rounded-2xl border border-[#d4dff0] bg-white p-5">
      <h3 className="text-sm font-bold mb-3" style={{ color: "#0D2461" }}>Historial de pagos</h3>
      <div className="h-16 flex items-center justify-center text-gray-400 text-sm">Cargando…</div>
    </div>
  );

  return (
    <div className="mt-6 rounded-2xl border border-[#d4dff0] bg-white p-5">
      <h3 className="text-sm font-bold mb-4" style={{ color: "#0D2461" }}>Historial de pagos</h3>
      {events.length === 0 ? (
        <p className="text-sm text-gray-400 text-center py-4">No hay pagos registrados aún.</p>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-xs font-semibold text-gray-400 border-b border-[#eef2f8]">
                <th className="pb-2 pr-4">Fecha</th>
                <th className="pb-2 pr-4">Descripción</th>
                <th className="pb-2 pr-4">Plan</th>
                <th className="pb-2 pr-4 text-right">Monto</th>
                <th className="pb-2">Estado</th>
              </tr>
            </thead>
            <tbody>
              {events.map((ev) => {
                const s = STATUS_LABEL[ev.status] ?? { label: ev.status, color: "text-gray-500 bg-gray-50" };
                const date = new Date(ev.createdAt).toLocaleDateString("es-AR", { day: "2-digit", month: "2-digit", year: "numeric" });
                const amount = ev.amount != null && ev.amount > 0
                  ? `$${ev.amount.toLocaleString("es-AR")}`
                  : "—";
                return (
                  <tr key={ev.id} className="border-b border-[#eef2f8] last:border-0 hover:bg-[#f8faff] transition-colors">
                    <td className="py-3 pr-4 text-xs text-gray-500 whitespace-nowrap">{date}</td>
                    <td className="py-3 pr-4 text-gray-800 max-w-[180px] truncate">{ev.description || "—"}</td>
                    <td className="py-3 pr-4 text-gray-600 capitalize">{ev.plan}</td>
                    <td className="py-3 pr-4 text-right font-semibold text-gray-800 whitespace-nowrap">{amount}</td>
                    <td className="py-3">
                      <span className={`inline-flex px-2 py-0.5 rounded-full text-xs font-semibold whitespace-nowrap ${s.color}`}>
                        {s.label}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

